```aether:src/services/taskService.ts
import { AuditLogEntry, Task } from '../models/task';
import { mockTasks, mockAuditLogs } from '../data/mockData';

export class TaskService {
  /**
   * Retrieves the audit log history for a specific task.
   * @param taskId The ID of the task.
   * @returns An array of AuditLogEntry objects, sorted by timestamp.
   */
  public getTaskAuditLog(taskId: string): AuditLogEntry[] {
    // In a real application, this would query a database.
    // For this exercise, we filter mock data.
    const auditLogs = mockAuditLogs.filter(log => log.taskId === taskId);

    // Sort logs by timestamp in ascending order
    auditLogs.sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());

    return auditLogs;
  }

  /**
   * Checks if a task exists.
   * @param taskId The ID of the task.
   * @returns True if the task exists, false otherwise.
   */
  public taskExists(taskId: string): boolean {
    return mockTasks.some(task => task.id === taskId);
  }
}
```

```aether:src/routes/tasks.ts
import { Hono } from 'hono';
import { TaskService } from '../services/taskService';

const tasksRouter = new Hono();
const taskService = new TaskService();

/**
 * GET /tasks/:id/audit-log
 * Returns the audit log history for a single task.
 */
tasksRouter.get('/:id/audit-log', async (c) => {
  const taskId = c.req.param('id');

  if (!taskService.taskExists(taskId)) {
    return c.json({ message: `Task with ID '${taskId}' not found.` }, 404);
  }

  const auditLogs = taskService.getTaskAuditLog(taskId);

  // Hono automatically serializes the object to JSON
  return c.json(auditLogs);
});

export default tasksRouter;
```

