import { Hono } from 'hono';
import tasksRouter from './routes/tasks';

const app = new Hono();

// Mount the tasks router under the /api/tasks path
app.route('/api/tasks', tasksRouter);

// Basic root route
app.get('/', (c) => {
  return c.text('Aether Task Audit Log API is running!');
});

// Global error handler
app.onError((err, c) => {
  console.error(`${err}`);
  return c.json({ message: 'An internal server error occurred.' }, 500);
});

const port = 3000;
console.log(`Server is running on http://localhost:${port}`);

// Export the app for Vercel or other serverless environments,
// or directly run it with Node.js
export default {
  port,
  fetch: app.fetch,
};
